import { successResponse, outputAndExit, errorResponse } from '@/cli/output';
import {
  loadUserOrigins,
  addUserOrigin,
  removeUserOrigin,
} from '@/shared/user-origins';
import { PRIMARY_ORIGINS, ORIGIN_METADATA } from '@/shared/descriptions';
import { resolveOrigin } from '../lib/resolve-origin';
import { ensureProtocol } from '@/shared/url';

import type { Command } from '@/types';
import type { DiscoverResourcesInput } from '@/operations/discover';

const SURFACE = 'cli:origins';

export const originsAddCommand: Command<
  DiscoverResourcesInput
> = async input => {
  const resolved = await resolveOrigin(SURFACE, input);
  if (!resolved.ok) return outputAndExit(resolved.error, input);

  const origin = addUserOrigin(resolved.origin);

  return outputAndExit(
    successResponse({
      url: origin.url,
      title: origin.title,
      description: origin.description,
      note: 'Restart your MCP server for this origin to appear in the model context.',
      warnings: resolved.origin.warnings,
    }),
    input
  );
};

export const originsListCommand: Command = input => {
  const primary = PRIMARY_ORIGINS.flatMap(o => {
    const meta = ORIGIN_METADATA[o];
    return meta
      ? [{ url: o, title: meta.title, description: meta.description }]
      : [];
  });
  const added = loadUserOrigins();

  return outputAndExit(successResponse({ primary, added }), input);
};

export const originsRemoveCommand: Command<{
  url: string;
}> = input => {
  const url = ensureProtocol(input.url);

  const result = removeUserOrigin(url);

  if (!result.removed) {
    const isPrimary = PRIMARY_ORIGINS.some(o => String(o) === url);
    return outputAndExit(
      errorResponse(
        isPrimary
          ? {
              code: 'GENERAL_ERROR',
              message: `Cannot remove primary origin: ${url}. Only user-added origins can be removed.`,
              surface: SURFACE,
              cause: 'primary_origin',
            }
          : {
              code: 'GENERAL_ERROR',
              message: `Origin not found: ${url}`,
              surface: SURFACE,
              cause: 'not_found',
            }
      ),
      input
    );
  }

  return outputAndExit(successResponse({ removed: true, url }), input);
};
